parameters.jsCode:
const raw = $input.first().json;
const idiqs = $('Get Monitored IDIQs').all().map(i => i.json);

let allOpps = [];
try {
  const data = typeof raw === 'string' ? JSON.parse(raw) : raw;
  allOpps = data.opportunitiesData || data.items || [];
} catch(e) { allOpps = []; }

// Filter for task orders (type 'o') and match against our IDIQ vehicle list
const matched = [];
const vehicleNumbers = idiqs.map(v => (v.piid || v.contract_number || '').toLowerCase()).filter(Boolean);
const vehicleNames = idiqs.map(v => (v.vehicle_name || '').toLowerCase()).filter(Boolean);

for (const opp of allOpps) {
  const title = (opp.title || opp.opportunityTitle || '').toLowerCase();
  const desc = (opp.description || '').toLowerCase();
  const refNum = (opp.referenceNumber || opp.solicitationNumber || '').toLowerCase();

  const isMatch = vehicleNumbers.some(v => v && (refNum.includes(v) || desc.includes(v)))
    || vehicleNames.some(v => v && (title.includes(v) || desc.includes(v)));

  if (isMatch || opp.ntype === 'o') {
    const matchedVehicle = idiqs.find(v =>
      refNum.includes((v.piid||'').toLowerCase()) ||
      title.includes((v.vehicle_name||'').toLowerCase())
    );
    matched.push({
      title: opp.title || opp.opportunityTitle || 'Unknown',
      agency: opp.departmentName || opp.fullParentPathName || '',
      naics: opp.naicsCode || '',
      type: opp.type || opp.ntype || 'o',
      posted_date: opp.postedDate || '',
      response_deadline: opp.responseDeadLine || '',
      solicitation_number: opp.solicitationNumber || '',
      link: opp.uiLink || ('https://sam.gov/opp/' + (opp.noticeId || '')),
      matched_vehicle: matchedVehicle ? matchedVehicle.vehicle_name : 'General TO',
      matched_vehicle_id: matchedVehicle ? matchedVehicle.id : null,
      estimated_value: opp.awardAmount || null
    });
  }
}

return matched.length > 0
  ? matched.map(m => ({json: m}))
  : [{json: {_no_results: true}}];
